<html>
<head>
  <title>Симулятор свидания</title>
  <script src="https://cdn.jsdelivr.net/npm/socket.io@2.3.0/dist/socket.io.js"></script>
  <script>
    var socket = io.connect('http://localhost:3000');

    // Функция отправки сообщения
    function sendMessage(message) {
      socket.emit('message', message);
    }

    // Функция обновления интерфейса
    function updateInterface(gameState) {
      // Обновляем элементы на странице
      document.getElementById('chat-log').innerHTML += `<p>${gameState.message}</p>`;
      document.getElementById('player-name').textContent = gameState.playerName;
    }

    // Слушатель события приема сообщений
    socket.on('response', (response) => {
      updateInterface(response);
    });

    // Слушатель события обновления состояния игры
    socket.on('update', (gameState) => {
      updateInterface(gameState);
    });
  </script>
</head>
<body>
  <h1>Симулятор свидания</h1>
  <input id="player-name" type="text" placeholder="Ваше имя">
  <button onclick="sendMessage(document.getElementById('player-name').value)">Отправить</button>
  <div id="chat-log"></div>
</body>
</html>
```
5. Создайте файл `index.js`, который будет содержать логику для обработки сообщений:
```javascript
