To dynamically load tables from a database using Bootstrap Table, you can use the `ajax` option and specify the URL of your PHP script that will retrieve the data.

Here's an example:
```php
<div>
    <select id="table-dropdown">
        <option value="">Выберите таблицу</option>
        <?php foreach ($tables as $table): ?>
            <option value="<?php echo $table['name']; ?>"><?php echo $table['name']; ?></option>
        <?php endforeach; ?>
    </select>
    <table
        id="table"
        data-toggle="table"
        data-ajax="loadData"
        data-ajax-url="<?php echo site_url('admin/load_data'); ?>"
        data-ajax-method="get"
        data-ajax-data="{'tableName': $('#table-dropdown').val()}"
        ...
    </table>
</div>

<script>
    function loadData(params) {
        $.ajax({
            type: 'GET',
            url: params.ajax.url,
            data: params.ajax.data,
            success: function(data) {
                $('#table').bootstrapTable('load', data);
            }
        });
    }
</script>
```
In this example, we have a dropdown menu with options for each table name. When the user selects a table, the `data-ajax-url` attribute is updated to point to a PHP script (`site_url('admin/load_data')`) that will retrieve the data for the selected table.

The `data-ajax-method` attribute specifies the HTTP method (in this case, GET), and the `data-ajax-data` attribute passes the selected table name as a parameter to the PHP script.

On the server-side, you would create a PHP script that retrieves the data for the selected table and returns it in a format that Bootstrap Table expects (e.g., JSON). For example:
```php
<?php
$table_name = $_GET['tableName'];
$query = "SELECT * FROM `$table_name`";
$results = mysqli_query($conn, $query);

$data = array();
while ($row = mysqli_fetch_assoc($results)) {
    $data[] = $row;
}

echo json_encode($data);
?>
```
This script assumes you're using MySQLi extension for database operations. You'll need to modify it according to your specific database setup.

When the user selects a new table, the `loadData` function is called, which sends a GET request to the PHP script with the selected table name as a parameter. The script retrieves the data and returns it as JSON, which is then loaded into the table using Bootstrap Table's `load` method.

Программа будет выглядеть следующим образом:

```cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

struct Student {
    int age;
    double height;
    double averageGrade;
    // добавить другие поля для других параметров
};

bool isUnique(const vector<Student>& students, int column, int studentIndex) {
    for (int i = 0; i < students.size(); ++i) {
        if (i != studentIndex && abs(students[i].age - students[studentIndex].age) == 0 || // замените age на соответствующий параметр
            abs(students[i].height - students[studentIndex].height) == 0 ||
            abs(students[i].averageGrade - students[studentIndex].averageGrade) == 0) {
            return false;
        }
    }
    return true;
}

bool isAverage(const vector<Student>& students, int column, int studentIndex) {
    double sum = 0;
    for (const auto& student : students) {
        sum += student.column; // замените column на соответствующий параметр
    }
    sum /= students.size();
    return abs(sum - students[studentIndex].column) <= 1e-6; // замените column на соответствующий параметр
}

int main() {
    const int n = 5; // количество строк (учеников)
    const int m = 4; // количество столбцов (параметров)

    // инициализация матрицы в динамической памяти
    vector<vector<int>> matrix(n, vector<int>(m));
    // заполнение матрицы

    // или инициализация матрицы в статической памяти
    // const int matrix[n][m] = {{...}};

    vector<Student> students(n);
    for (int i = 0; i < n; ++i) {
        students[i].age = matrix[i][0];
        students[i].height = matrix[i][1];
        students[i].averageGrade = matrix[i][2];
        // добавьте остальные поля
    }

    // найти числа уникальных и средних студентов
    vector<int> uniqueStudents;
    vector<int> averageStudents;
    for (int i = 0; i < n; ++i) {
        bool isUniq = true;
        bool isAvg = true;
        for (int j = 0; j < m; ++j) {
            if (!isUnique(students, j, i)) {
                isUniq = false;
                break;
            }
            if (!isAverage(students, j, i)) {
                isAvg = false;
                break;
            }
        }
        if (isUniq && isAvg) {
            uniqueStudents.push_back(i + 1); // +1 потому что индексация начинается с 0
            averageStudents.push_back(i + 1);
        } else if (isUniq) {
            uniqueStudents.push_back(i + 1);
        } else if (isAvg) {
            averageStudents.push_back(i + 1);
        }
    }

    cout << "Уникальные студенты: ";
    for (const auto& student : uniqueStudents) {
        cout << student << " ";
    }
    cout << endl;

    cout << "Средние студенты: ";
    for (const auto& student : averageStudents) {
        cout << student << " ";
    }
    cout << endl;

    cout << "Средние среди уникальных: ";
    vector<int> uniqueAverageStudents;
    for (const auto& student : uniqueStudents) {
        bool isAvg = true;
        for (int j = 0; j < m; ++j) {
            if (!isAverage(students, j, student - 1)) { // -1 потому что индексация начинается с 0
                isAvg = false;
                break;
            }
        }
        if (isAvg) {
            uniqueAverageStudents.push_back(student);
        }
    }
    for (const auto& student : uniqueAverageStudents) {
        cout << student << " ";
    }
    cout << endl;

    cout << "Уникальные среди средних: ";
    vector<int> averageUniqueStudents;
    for (const auto& student : averageStudents) {
        bool isUniq = true;
        for (int j = 0; j < m; ++j) {
            if (!isUnique(students, j, student - 1)) { // -1 потому что индексация начинается с 0
                isUniq = false;
                break;
            }
        }
        if (isUniq) {
            averageUniqueStudents.push_back(student);
        }
    }
    for (const auto& student : averageUniqueStudents) {
        cout << student << " ";
    }
    cout << endl;

    return 0;
}
```

В программе реализованы функции `isUnique` и `isAverage`, которые проверяют является ли студент уникальным или средним соответственно. Затем программа находит числа уникальных и средних студентов, а также студентов, которые являются одновременно уникальными и средними.

