Вот пример implementation of a class that draws an amplitude directional diagram using Qt and Qt3DRender:
```cpp
#include <QVector>
#include <QVector3D>
#include <QVector4D>
#include <QMatrix4x4>
#include <QOpenGLContext>
#include <QOpenGLFunctions>
#include <Qt3DExtras/QAbstractTexture>
#include <Qt3DRender/QMesh>

class AmplitudeDirectionalDiagram {
public:
    AmplitudeDirectionalDiagram(QWidget* parent = nullptr)
        : QWidget(parent) {}

    void setValues(const QVector<double>& elevationAngles, const QVector<double>& azimuthAngles, const QVector<double>& amplitudes) {
        m_elevationAngles = elevationAngles;
        m_azimuthAngles = azimuthAngles;
        m_amplitudes = amplitudes;

        update();
    }

protected:
    void paintEvent(QPaintEvent* event) override {
        QPainter painter(this);
        painter.setRenderHint(QPainter::Antialiasing);

        // Create a 3D scene
        Qt3DCore::QEntity* rootEntity = new Qt3DCore::QEntity();
        Qt3DRender::QScene* scene = new Qt3DRender::QScene(rootEntity);

        // Create a sphere to represent the amplitude directional diagram
        Qt3DExtras::QSphereMesh* sphereMesh = new Qt3DExtras::QSphereMesh();
        sphereMesh->setRadius(1.0f);
        Qt3DCore::QTransform* transform = new Qt3DCore::QTransform(sphereMesh);
        transform->setTranslation(QVector3D(0.0f, 0.0f, 0.0f));
        rootEntity->addComponent(transform);

        // Create a texture to store the amplitude values
        Qt3DExtras::QTexture2D* texture = new Qt3DExtras::QTexture2D();
        texture->setSize(512, 512);
        rootEntity->addComponent(texture);

        // Calculate the amplitude values in spherical coordinates
        for (int i = 0; i < m_elevationAngles.size(); ++i) {
            double elevation = m_elevationAngles[i];
            double azimuth = m_azimuthAngles[i];
            double amplitude = m_amplitudes[i];

            // Convert spherical coordinates to Cartesian coordinates
            float x = sin(elevation * M_PI / 180.0f) * cos(azimuth * M_PI / 180.0f);
            float y = sin(elevation * M_PI / 180.0f) * sin(azimuth * M_PI / 180.0f);
            float z = cos(elevation * M_PI / 180.0f);

            // Map the amplitude value to a color
            QColor color = QColor::fromHslF((amplitude + 1.0f) / 2.0f, 1.0f, 1.0f);
            texture->setColor(color);

            // Set the vertex data
            int vertexIndex = static_cast<int>(texture->vertexCount());
            texture->addVertex(vertexIndex, QVector3D(x, y, z));
            texture->addColor(vertexIndex, color);
            texture->addNormal(vertexIndex, QVector3D(0.0f, 0.0f, 1.0f));
        }

        // Render the scene
        Qt3DRender::QCamera* camera = new Qt3DRender::QCamera();
        camera->setPosition(QVector3D(0.0f, 0.0f, 5.0f));
        camera->lookAt(QVector3D(0.0f, 0.0f, 0.0f));

        Qt3DRender::QRenderSettings* renderSettings = new Qt3DRender::QRenderSettings();
        renderSettings->setActiveCamera(camera);

        Qt3DRender::QRenderer* renderer = new Qt3DRender::QRenderer(scene);
        renderer->setRenderSettings(renderSettings);

        // Update the scene
        scene->update();

        // Render the scene to a QImage
        QImage image(512, 512, QImage::Format_RGB32);
        QPainter painter(&image);
        painter.setRenderHint(QPainter::Antialiasing);
        renderer->render(&painter);

        // Draw the rendered image on the widget
        painter.begin(this);
        painter.drawImage(0, 0, image);
        painter.end();
    }

private:
    QVector<double> m_elevationAngles;
    QVector<double> m_azimuthAngles;
    QVector<double> m_amplitudes;
};
```
This class uses the `QVector` class to store the input values, and the `QPainter` and `QImage` classes to render the amplitude directional diagram.

The `paintEvent` method is overridden to create a 3D scene using Qt3DRender, and then renders the scene to a `QImage`. The rendered image is then drawn on the widget using `QPainter`.

In the `paintEvent` method, the amplitude values are converted from spherical coordinates to Cartesian coordinates using the following formula:

x = sin(elevation * π / 180.0f) * cos(azimuth * π / 180.0f)
y = sin(elevation * π / 180.0f) * sin(azimuth * π / 180.0f)
z = cos(elevation * π / 180.0f)

The amplitude value is then mapped to a color using the HSL color space, and the resulting color is used to set the vertex data for the texture.

Note that this implementation assumes that the input values are in degrees, so you may need to adjust the conversion formulas accordingly if your input values are in radians.

You can use this class as follows:
```cpp
AmplitudeDirectionalDiagram* diagram = new AmplitudeDirectionalDiagram();
diagram->setValues(elevationAngles, azimuthAngles, amplitudes);
diagram->show();
```
Make sure to include the necessary headers and link against the Qt3DRender library when compiling your code.

