answer:
Вот пример реализации класса `Set` на языке C++:
```cpp
#include <iostream>
#include <vector>
#include <algorithm>

template <typename T>
class Set {
private:
    std::vector<T> elements;

public:
    // Конструктор по умолчанию
    Set() {}

    // Конструктор с параметром
    Set(T* arr, int size) {
        for (int i = 0; i < size; ++i) {
            add(arr[i]);
        }
    }

    // Добавление элемента в множество
    void add(T element) {
        if (!contains(element)) {
            elements.push_back(element);
        }
    }

    // Добавление группы элементов в множество
    void add(T* arr, int size) {
        for (int i = 0; i < size; ++i) {
            add(arr[i]);
        }
    }

    // Удаление элемента из множества
    void del(T element) {
        auto it = std::find(elements.begin(), elements.end(), element);
        if (it != elements.end()) {
            elements.erase(it);
        }
    }

    // Проверка вхождения элемента в множество
    bool contains(T element) const {
        return std::find(elements.begin(), elements.end(), element) != elements.end();
    }

    // Печать элементов множества
    void print() const {
        std::cout << "{";
        for (const auto& elem : elements) {
            std::cout << elem << " ";
        }
        std::cout << "}\n";
    }

    // Пересечение множеств
    Set operator*(const Set& other) const {
        Set result;
        for (const auto& elem : elements) {
            if (other.contains(elem)) {
                result.add(elem);
            }
        }
        return result;
    }

    // Объединение множеств
    Set operator+(const Set& other) const {
        Set result;
        result.elements = elements;
        for (const auto& elem : other.elements) {
            if (!result.contains(elem)) {
                result.add(elem);
            }
        }
        return result;
    }
};

int main() {
    int a[] = { 1, 2, 3, 4, 5 };
    int b[] = { 3, 2, 6 };

    Set<int> seti1(a, 5), seti2, seti3, seti4;
    seti2.add(b, 3);

    seti1.print();
    seti2.print();

    seti3 = seti1 * seti2;
    std::cout << "Intersect: ";
    seti3.print();

    seti3 = seti1 + seti2;
    std::cout << "Union: ";
    seti3.print();

    return 0;
}
```
В этом примере мы используем вектор (`std::vector`) для хранения элементов множества. Мы перегружаем операции `add`, `del`, `contains`, `operator*` и `operator+` для работы с множествами.

В методе `add` мы проверяем, не содержится ли элемент уже в множестве, если нет, то добавляем его в конец вектора.

Метод `del` удаляет элемент из вектора, если он существует.

Метод `contains` проверяет, содержится ли элемент в множестве.

Метод `print` выводит элементы множества в формате `{a b c ...}`.

Метод `operator*` возвращает новое множество, которое является пересечением двух множеств.

Метод `operator+` возвращает новое множество, которое является объединением двух множеств.

В примере программы мы создаем два множества `seti1` и `seti2`, добавляем элементы в них, печатаем их, затем создаем третье множество `seti3` как пересечение `seti1` и `seti2`, а затем как объединение `seti1` и `seti2`.

