Напиши функцию javascript, которая принимает Vector {x,y,z} и возвращает объект со свойствами right, left, back, forward, и значения этих свойств были векторами направления в эти стороны относительно входного вектора. Примеры того как функция должна работать: {x:0, y: 0, z:-1} => { left: {x:-1, y: 0, z:0}, right: {x:1, y: 0, z:0}, forward: {x:0, y: 0, z:-1}, back: {x:0, y: 0, z:1}, }

{x:0, y: 0, z:1} => { left: {x:1, y: 0, z:0}, right: {x:-1, y: 0, z:0}, forward: {x:0, y: 0, z:1}, back: {x:0, y: 0, z:-1}, }

{x:-1, y: 0, z:0} => { left: {x:0, y: 0, z:1}, right: {x:0, y: 0, z:-1}, forward: {x:-1, y: 0, z:0}, back: {x:1, y: 0, z:0}, }

{x:1, y: 0, z:0} => { left: {x:0, y: 0, z:-1}, right: {x:0, y: 0, z:1}, forward: {x:1, y: 0, z:0}, back: {x:-1, y: 0, z:0}, }

answer:
Вот функция JavaScript, которая выполняет описанные требования:
```
function getDirections(vector) {
  const result = {};

  if (vector.x === 0 && vector.y === 0) {
    // если x и y равны нулю, то направление только по оси z
    if (vector.z > 0) {
      result.forward = {x: 0, y: 0, z: -1};
      result.back = {x: 0, y: 0, z: 1};
    } else {
      result.forward = {x: 0, y: 0, z: 1};
      result.back = {x: 0, y: 0, z: -1};
    }
  } else if (Math.abs(vector.x) > Math.abs(vector.y)) {
    // если x больше или равно y, то направление по осям x и z
    if (vector.x < 0) {
      result.left = {x: 0, y: 0, z: 1};
      result.right = {x: 0, y: 0, z: -1};
      result.forward = {x: -1, y: 0, z: 0};
      result.back = {x: 1, y: 0, z: 0};
    } else {
      result.left = {x: 0, y: 0, z: -1};
      result.right = {x: 0, y: 0, z: 1};
      result.forward = {x: 1, y: 0, z: 0};
      result.back = {x: -1, y: 0, z: 0};
    }
  } else {
    // если y больше x, то направление по осям y и z
    if (vector.y < 0) {
      result.left = {x: 1, y: 0, z: 0};
      result.right = {x: -1, y: 0, z: 0};
      result.forward = {x: 0, y: -1, z: 0};
      result.back = {x: 0, y: 1, z: 0};
    } else {
      result.left = {x: -1, y: 0, z: 0};
      result.right = {x: 1, y: 0, z: 0};
      result.forward = {x: 0, y: 1, z: 0};
      result.back = {x: 0, y: -1, z: 0};
    }
  }

  return result;
}
```
Функция анализирует входной вектор и определяет направления left, right, forward и back в зависимости от значений компонентов вектора. Если один из компонентов имеет наибольшее значение, то функция определит направление соответственно. Если все компоненты имеют равные значения, то функция определит направление по оси z.

Вы можете проверить работу этой функции, вызвав ее с различными векторами, например:
```
console.log(getDirections({x: 0, y: 0, z: -1}));
console.log(getDirections({x: 0, y: 0, z: 1}));
console.log(getDirections({x: -1, y: 0, z: 0}));
console.log(getDirections({x: 1, y: 0, z: 0}));
```

