using System.IO;
using System.Linq;

public class MicroscopyImage
{
    public int Id { get; set; }
    public MicroscopySample Sample { get; set; }
    public byte[] ImageData { get; set; }
    public string ImageMimeType { get; set; }

    public void Save(string filePath)
    {
        using (var fileStream = File.Create(filePath))
        {
            fileStream.Write(ImageData, 0, ImageData.Length);
        }
    }

    public static MicroscopyImage Load(string filePath)
    {
        using var fileStream = File.OpenRead(filePath);
        var imageData = new byte[fileStream.Length];
        fileStream.Read(imageData, 0, imageData.Length);
        return new MicroscopyImage
        {
            ImageData = imageData,
            ImageMimeType = MimeTypes.GetMimeTypeFromFilePath(filePath)
        };
    }
}

public static class MimeTypes
{
    private static readonly Dictionary<string, string> _mimeTypes = new Dictionary<string, string>
    {
        {"image/jpeg", "jpg"},
        {"image/png", "png"}
    };

    public static string GetMimeTypeFromFilePath(string filePath)
    {
        var extension = Path.GetExtension(filePath).ToLower();
        if (_mimeTypes.TryGetValue(extension, out var mimeType))
        {
            return mimeType;
        }
        throw new ArgumentException($"Unknown MIME type for file extension {extension}", nameof(filePath));
    }
}
```
API для созданных классов:
```csharp
[ApiController]
[Route("api/[controller]")]
public class MicroscopyController : ControllerBase
{
    private readonly List<MicroscopyTest> _tests = new List<MicroscopyTest>();

    [HttpGet]
    public IActionResult GetAllTests()
    {
        return Ok(_tests);
    }

    [HttpPost]
    public IActionResult CreateTest([FromBody] MicroscopyTest test)
    {
        _tests.Add(test);
        return CreatedAtAction(nameof(GetAllTests), new { id = test.Id }, test);
    }

    [HttpGet("{testId}")]
    public IActionResult GetTest(int testId)
    {
        var test = _tests.FirstOrDefault(t => t.Id == testId);
        if (test == null)
        {
            return NotFound();
        }
        return Ok(test);
    }

    [HttpPost("{testId}/samples")]
    public IActionResult AddSampleToTest(int testId, [FromBody] MicroscopySample sample)
    {
        var test = _tests.FirstOrDefault(t => t.Id == testId);
        if (test == null)
        {
            return NotFound();
        }
        test.Samples.Add(sample);
        return Accepted();
    }

    [HttpGet("{testId}/samples/{sampleId}")]
    public IActionResult GetSampleFromTest(int testId, int sampleId)
    {
        var test = _tests.FirstOrDefault(t => t.Id == testId);
        if (test == null)
        {
            return NotFound();
        }
        var sample = test.Samples.FirstOrDefault(s => s.Id == sampleId);
        if (sample == null)
        {
            return NotFound();
        }
        return Ok(sample);
    }

    [HttpPost("{testId}/images")]
    public IActionResult UploadImage(int testId, [FromBody]byte[] imageData)
    {
        var test = _tests.FirstOrDefault(t => t.Id == testId);
        if (test == null)
        {
            return NotFound();
        }
        var image = new MicroscopyImage
        {
            Sample = test.Samples.Last(),
            ImageData = imageData
        };
        // сохраняем изображение на диск
        image.Save($@"C:\MicroscopyImages\{image.Sample.SampleName}.jpg");
        return Accepted();
    }
}
```
В этом примере мы создали три класса: `MicroscopyTest`, `MicroscopySample` и `MicroscopyImage`. Класс `MicroscopyTest` represents a single microscopy test, with a list of samples associated with it. Класс `MicroscopySample` represents a single sample from a test, with properties for the sample name, description and date collected. Класс `MicroscopyImage` represents an image taken during a microscopy test, with properties for the image data and MIME type.

API включает в себя следующие методы:

* `GetAllTests`: возвращает список всех тестов
* `CreateTest`: создает новый тест
* `GetTest`: возвращает информацию о конкретном тесте
* `AddSampleToTest`: добавляет образец к тесту
